1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Scenario {
14	  customer: { yearsWithMHPCO: number };
15	  steps: QuoteStep[];
16	}
17	
18	const BASE_PREMIUM: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	};
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	const COMPONENT_BASE = 25;
28	const BLOCK_SIZE = 3;
29	const BLOCK_BASE = 60;
30	
31	const FIRST_INSURANCE_RATE = 0.1;
32	const CURSE_RATE = 0.5;
33	const PROCESSING_FEE = 5;
34	const ROUNDING_PRECISION = 6;
35	
36	const componentGroupBase = (count: number): number =>
37	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
38	
39	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
40	
41	const mainItemPremium = (item: Item): number => {
42	  const base = BASE_PREMIUM[item.type];
43	  const surchargeRate = FIRST_INSURANCE_RATE + (item.cursed ? CURSE_RATE : 0);
44	  return base + base * surchargeRate;
45	};
46	
47	const mainItemTotal = (items: Item[]): number =>
48	  items
49	    .filter((item) => !isComponent(item))
50	    .reduce((sum, item) => sum + mainItemPremium(item), 0);
51	
52	const componentTotal = (items: Item[]): number => {
53	  const counts: Record<string, number> = {};
54	  for (const item of items.filter(isComponent)) {
55	    counts[item.type] = (counts[item.type] ?? 0) + 1;
56	  }
57	  const base = Object.values(counts).reduce((sum, count) => sum + componentGroupBase(count), 0);
58	  return base + base * FIRST_INSURANCE_RATE;
59	};
60	
61	const roundUpToWhole = (amount: number): number =>
62	  Math.ceil(Number(amount.toFixed(ROUNDING_PRECISION)));
63	
64	const quotePremium = (items: Item[]): number =>
65	  roundUpToWhole(mainItemTotal(items) + componentTotal(items) + PROCESSING_FEE);
66	
67	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
68	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
69	  return { results };
70	};
